import { ref, computed, onMounted } from 'vue';
import { useRouter } from 'vue-router';
import {
  SearchIcon,
  RefreshCwIcon,
  BuildingIcon,
  MapPinIcon,
  TagIcon,
  UsersIcon,
  ArrowRightIcon,
  ChevronLeftIcon,
  ChevronRightIcon,
} from 'lucide-vue-next';
import { universityApi } from '@/api/university';
import { VirtualList } from '@/components/common';
import type { University } from '@/types/university';
import type { UniversitySearchParams } from '@/types/api-params';
import { ElMessage } from 'element-plus';

const router = useRouter();

// 响应式数据
const loading = ref(false);
const hasSearched = ref(false);
const currentPage = ref(1);
const pageSize = 10;
const sortBy = ref('name');
const totalCount = ref(0);

// 搜索表单
const searchForm = ref({
  name: '',
  province: '',
  type: '',
  level: '',
});

// 省份列表
const provinces = ref([
  '北京',
  '上海',
  '天津',
  '重庆',
  '河北',
  '山西',
  '辽宁',
  '吉林',
  '黑龙江',
  '江苏',
  '浙江',
  '安徽',
  '福建',
  '江西',
  '山东',
  '河南',
  '湖北',
  '湖南',
  '广东',
  '广西',
  '海南',
  '四川',
  '贵州',
  '云南',
  '西藏',
  '陕西',
  '甘肃',
  '青海',
  '宁夏',
  '新疆',
  '内蒙古',
  '台湾',
  '香港',
  '澳门',
]);

// 院校数据
const universities = ref<University[]>([]);

// 计算属性

const totalPages = computed(() => Math.ceil(totalCount.value / pageSize));

const paginatedUniversities = computed(() => {
  const start = (currentPage.value - 1) * pageSize;
  const end = start + pageSize;
  return universities.value.slice(start, end);
});

// 方法
const handleSearch = async () => {
  loading.value = true;
  hasSearched.value = true;
  currentPage.value = 1;

  try {
    const params: UniversitySearchParams = {
      page: currentPage.value,
      limit: pageSize,
    };

    if (searchForm.value.name) {
      params.keyword = searchForm.value.name;
    }
    if (searchForm.value.province) {
      params.province = searchForm.value.province;
    }
    if (searchForm.value.type) {
      params.type = searchForm.value.type;
    }
    if (searchForm.value.level) {
      params.level = searchForm.value.level;
    }

    const response = await universityApi.search(params);
    if (response.success && response.data) {
      universities.value = response.data.universities || [];
      totalCount.value = response.data.total || 0;
    } else {
      universities.value = [];
      totalCount.value = 0;
    }

    ElMessage.success(`找到 ${totalCount.value} 所院校`);
  } catch (error) {
    console.error('搜索院校失败:', error);
    ElMessage.error('搜索院校失败，请稍后重试');
  } finally {
    loading.value = false;
  }
};

const resetSearch = () => {
  searchForm.value = {
    name: '',
    province: '',
    type: '',
    level: '',
  };
  hasSearched.value = false;
  currentPage.value = 1;
  universities.value = [];
};

const handleSort = () => {
  currentPage.value = 1;
};

const viewUniversityDetail = (university: University) => {
  router.push(`/universities/${university.id}`);
};

// 生命周期
onMounted(() => {
  // 初始化数据 - 加载热门院校
  handleSearch();
});
</script>

