  <div class="recommendation-page">
    <div class="container">
      <div class="page-header">
        <h1 class="page-title">AI智能推荐</h1>
        <p class="page-subtitle">
          基于大数据分析和AI算法，为您量身定制最优志愿方案
        </p>
      </div>

