  max-width: 600px;
  margin: 20px auto 0;
  text-align: left;
}

.error-stack {
  background: #f5f7fa;
  padding: 16px;
  border-radius: 4px;
  font-size: 12px;
  overflow-x: auto;
  white-space: pre-wrap;
  word-break: break-all;
  color: #606266;
}

/* Dark mode */
:deep(.dark) .error-stack {
  background: #374151;
  color: #d1d5db;
}
</style>","type":"text"},{"text":"
