<template>
  <div class="payment-form">
    <h2>选择会员套餐</h2>
    <div class="plan-selection">
      <div
        v-for="plan in plans"
        :key="plan.plan_code"
        :class="['plan-card', { selected: selectedPlan === plan.plan_code }]"
        @click="selectPlan(plan.plan_code)"
      >
