  '宁夏',
  '新疆',
  '内蒙古',
  '台湾',
  '香港',
  '澳门',
]);

// 院校数据
const universities = ref<University[]>([]);

// 计算属性

const totalPages = computed(() => Math.ceil(totalCount.value / pageSize));

// 后端已分页，直接使用返回数据
const paginatedUniversities = computed(() => universities.value);

// 方法
const handleSearch = async (resetPage = true) => {
  loading.value = true;
  hasSearched.value = true;
  if (resetPage) {
    currentPage.value = 1;
  }

  try {
    const params: UniversitySearchParams = {
      page: currentPage.value,
      limit: pageSize,
    };

    if (searchForm.value.name) {
      params.keyword = searchForm.value.name;
    }
    if (searchForm.value.province) {
      params.province = searchForm.value.province;
    }
    if (searchForm.value.type) {
      params.type = searchForm.value.type;
    }
    if (searchForm.value.level) {
      params.level = searchForm.value.level;
    }

    const response = await universityApi.search(params);
    if (response.success && response.data) {
      universities.value = response.data.universities || [];
      totalCount.value = response.data.total || 0;
    } else {
      universities.value = [];
      totalCount.value = 0;
    }

    ElMessage.success(`找到 ${totalCount.value} 所院校`);
  } catch (error) {
    console.error('搜索院校失败:', error);
    ElMessage.error('搜索院校失败，请稍后重试');
  } finally {
    loading.value = false;
  }
};

const resetSearch = () => {
  searchForm.value = {
    name: '',
    province: '',
    type: '',
    level: '',
  };
  hasSearched.value = false;
  currentPage.value = 1;
  universities.value = [];
};

const handleSort = () => {
  currentPage.value = 1;
};

const handlePageChange = (newPage: number) => {
  currentPage.value = newPage;
  handleSearch(false);
};

const viewUniversityDetail = (university: University) => {
