    const jwtArbitrary = fc.tuple(
      fc.base64String({ minLength: 10, maxLength: 50 }),
      fc.base64String({ minLength: 10, maxLength: 100 }),
      fc.base64String({ minLength: 10, maxLength: 50 })
    ).map(([header, payload, signature]) => 
      `${header}.${payload}.${signature}`.replace(/[+/=]/g, '')
    )

