  } catch (err) {
    major.value = null;
    error.value = err instanceof Error ? err.message : '获取专业详情失败';
  } finally {
    loading.value = false;
  }
};

const goBack = () => {
  router.push('/majors');
};

onMounted(fetchDetail);
watch(() => route.params.id, fetchDetail);
</script>
